#include "qp/portfolio/portfolio.hpp"
namespace qp::portfolio { Portfolio::Portfolio(double initial_cash): cash_(initial_cash){} Position Portfolio::position(const Symbol& s) const { auto it=positions_.find(s); return it==positions_.end()?Position{Quantity{0.0}, Price{0.0}}:it->second; } Result<void> Portfolio::buy(const Symbol& s, Quantity q, Price p, double fee){ if(!q.is_positive()||!p.is_positive()) return Err(Error{ErrorCode::InvalidArgument,"invalid buy quantity or price"}); double cost=q.value*p.value+fee; if(cost>cash_) return Err(Error{ErrorCode::InvalidArgument,"insufficient cash"}); auto& pos=positions_[s]; double old_qty=pos.quantity.value; double new_qty=old_qty+q.value; pos.average_price=Price{new_qty>0?(old_qty*pos.average_price.value+q.value*p.value)/new_qty:0.0}; pos.quantity=Quantity{new_qty}; cash_-=cost; return Ok(); } Result<void> Portfolio::sell(const Symbol& s, Quantity q, Price p, double fee){ if(!q.is_positive()||!p.is_positive()) return Err(Error{ErrorCode::InvalidArgument,"invalid sell quantity or price"}); auto& pos=positions_[s]; if(q.value>pos.quantity.value) return Err(Error{ErrorCode::InvalidArgument,"cannot sell more than current long position"}); pos.quantity=Quantity{pos.quantity.value-q.value}; cash_ += q.value*p.value-fee; if(pos.quantity.value==0.0) pos.average_price=Price{0.0}; return Ok(); } double Portfolio::equity(const std::map<Symbol,Price>& marks) const { double e=cash_; for(const auto& [s,pos]:positions_){ auto it=marks.find(s); if(it!=marks.end()) e += pos.quantity.value*it->second.value; } return e; } }
